    document.getElementById('dataset').textContent = JSON.stringify(products, null, 2);

    const searchInput = document.getElementById('search');
    const modeSelect = document.getElementById('mode');
    const queryStrEl = document.getElementById('queryStr');
    const resultsEl = document.getElementById('results');

    function renderResults(queryString, rows) {
      queryStrEl.textContent = queryString;
      resultsEl.textContent = JSON.stringify(rows, null, 2);
    }

    // NOTE: The "vulnerable" mode is a simulation: it constructs a pseudo-query string
    // by concatenating the user input, then evaluates a very small, controlled evaluator
    // that supports expressions of the form "field = 'value'" and simple OR/AND with basic operators.
    //
    // This evaluator is intentionally minimal and safe: it only understands a restricted syntax
    // (field comparisons and boolean OR/AND) and will not execute arbitrary code.
    // It exists only to show how interpreting user text as part of a query changes results.
    //
    // The "safe" mode will not parse the input as a query expression — it will treat the whole
    // input string as a literal value for the 'name' field (parameterized style).

    // Minimal parser for simple expressions: supports OR, AND, comparisons like:
    // name = 'Pen'   price < 10   name = '' OR price < 10
