      } catch (e) {
        parsed = { type: 'or', clauses: [] };
      }
      const rows = products.filter(r => evalParsed(parsed, r));
      return { query: simulatedQuery, rows };
    }

    function runQuerySafe(userInput) {
      // Simulate parameterized query: SQL uses placeholder and value separately.
      // e.g. "SELECT * FROM products WHERE name = ?" with params [userInput]
      // In our simulation, we treat userInput as a value for the 'name' field ONLY.
      const simulatedQuery = "SELECT * FROM products WHERE name = ?";
      const param = userInput; // treated as data
      // We match rows where name === param (no parsing of param as code)
      const rows = products.filter(r => String(r.name) === String(param));
      return { query: simulatedQuery + "  -- params: [\"" + param + "\"]", rows };
    }

    function run() {
      const input = searchInput.value;
      const mode = modeSelect.value;
      if (mode === 'vulnerable') {
        const res = runQueryVulnerable(input);
        renderResults(res.query, res.rows);
      } else {
        // Safe mode: user input is treated as value for 'name'
        const res = runQuerySafe(input);
        renderResults(res.query, res.rows);
      }
    }

    document.getElementById('run').addEventListener('click', run);

