        if(!left || left.type !== "IDENT") throw new Error("Expected identifier");
        const op = consume();
        if(!op || (op.type !== "OP" && !(op.type==="IDENT" && op.value.toUpperCase()==="LIKE"))) {
          throw new Error("Expected operator");
