        let right = consume();
        if(!right || right.type !== "STRING" && right.type !== "IDENT" && right.type!=="CHAR") throw new Error("Expected literal");
        return {type:"CMP", left:left.value, op: (op.type==="OP"?op.value:op.value.toUpperCase()), right: right.value};
      }

      let node = parseComparison();
      while(peek() && peek().type === "BOOL"){
        const b = consume();
        const rhs = parseComparison();
        node = { type: b.value, left: node, right: rhs };
      }
      return node;
    }

    // Evaluate AST against a product
    function evalAst(node, p){
      if(node.type === "CMP"){
        const fld = node.left;
        const op = node.op;
        let val = node.right;
        // CHAR tokens may be % etc; treat as raw string token if provided
        if(typeof val !== "string") val = String(val);
        // emulate SQL semantics for our small demo
        if(op === "="){
          // strip surrounding percent characters if present? For equals, exact compare
          return String(p[fld]) === val;
        } else if(op === "LIKE"){
          // convert SQL-like with % to regex
          const pattern = val;
          const regex = new RegExp("^" + escapeForRegex(pattern).replace(/%/g,".*") + "$", "i");
          return regex.test(String(p[fld]));
        } else if(op === ">"){
          const a = Number(p[fld]), b = Number(val);
          return Number.isFinite(a) && Number.isFinite(b) && a > b;
        } else if(op === "<"){
          const a = Number(p[fld]), b = Number(val);
          return Number.isFinite(a) && Number.isFinite(b) && a < b;
        } else {
          return false;
        }
      } else if(node.type === "OR"){
        return evalAst(node.left, p) || evalAst(node.right, p);
      } else if(node.type === "AND"){
        return evalAst(node.left, p) && evalAst(node.right, p);
      }
      return false;
    }

    function escapeForRegex(s){
      return s.replace(/[-\/\\^$*+?.()|[\]{}]/g, '\\$&');
    }

