      const node = parseOr();
      consume(')');
      return node;
    }
    // parse condition: e.g. name LIKE "foo", category = "Books", price < 100
    const left = peek(); i++;
    const op = peek(); i++;
    const right = peek(); i++;
    return { type: 'cond', left, op, right };
  }

