    );
  }

  showResults(matched);
  explanationEl.innerHTML = [
    "<strong>What happened (vulnerable simulation):</strong>",
    "Because the query string was constructed by concatenating the user's input directly into the SQL-like text, certain inputs that include SQL operators (for example \"OR\", \"=\", or comment markers like \"--\") can change the logical structure of the query. In this simple simulation such inputs are treated as making the WHERE clause always true, so the query returns all rows.",
    "In real SQL, an input such as \"' OR '1'='1\" injected into a WHERE clause can turn a restrictive condition into a tautology unless the application properly separates data from code."
  ].join("\n\n");
}

function runSafe(userInput) {
