  // No matter what characters it contains (quotes, OR, equals, dashes), it cannot
  // change the structure of the SQL statement.
  // Here we perform a safe filtering equivalent to a LIKE with the parameter value:
  const paramLike = userInput.toLowerCase();
  let matched;
  if (paramLike === '') {
    matched = [];
  } else {
