            term = "'" + term + "'";
          }
          return "(String(p." + field + ").toLowerCase().includes(" + term.toLowerCase() + "))";
        })
        .replace(/\b([a-zA-Z_]+)\s*<\s*([0-9.]+)/g, '(p.$1 < $2)')
        .replace(/\b([a-zA-Z_]+)\s*>\s*([0-9.]+)/g, '(p.$1 > $2)');
      // Replace OR (case-insensitive) with ||
      expr = expr.replace(/\s+OR\s+/ig, ' || ');
      // If nothing recognizable, allow the raw input (this demonstrates vulnerability)
      if (!expr.trim()) expr = 'false';
      return expr;
    }

    // Safe mode: parse the input into parameter objects and apply fixed filter logic.
    function safeFilter(input) {
      const parsed = parseUserInput(input);
      // Build a description of the parameters (for display). Note: we never treat raw user text as code.
      safeQueryEl.textContent = JSON.stringify(parsed, null, 2);
      builtQueryEl.textContent = 'Not applicable in safe mode (no code-building from raw input)';

      // Apply filters deterministically: the app's code determines the structure, not the user input.
      // We permit only certain operators and treat user strings as data.
      const results = products.filter(p => {
        // If any OR-part matches, accept the product.
        return parsed.some(part => {
          if (part.kind === 'term') {
            const field = part.field;
            const value = String(part.value).toLowerCase();
            if (!(field in p)) return false;
            return String(p[field]).toLowerCase().includes(value);
          }
          if (part.kind === 'cmp') {
            const field = part.field;
            if (!(field in p) || typeof p[field] !== 'number') return false;
            if (part.op === '<') return p[field] < part.value;
            if (part.op === '>') return p[field] > part.value;
            return false;
          }
          if (part.kind === 'text') {
            // free text: match any string field that contains the raw text (treated as data)
            const raw = part.raw.toLowerCase();
            return ['name','category'].some(f => String(p[f]).toLowerCase().includes(raw));
          }
          return false;
        });
      });

      return results;
    }

    runBtn.addEventListener('click', () => {
      const input = document.getElementById('searchInput').value.trim();
      const mode = document.querySelector('input[name="mode"]:checked').value;
      let results;
      if (!input) {
        builtQueryEl.textContent = '—';
        safeQueryEl.textContent = '—';
        resultsEl.textContent = 'Please enter a search input.';
        return;
      }
      if (mode === 'vulnerable') {
        results = vulnerableFilter(input);
      } else {
        results = safeFilter(input);
      }
      resultsEl.textContent = JSON.stringify(results, null, 2);
    });

    // Pre-fill an example
    document.getElementById('searchInput').value = 'name:Phone OR price < 100';
    runBtn.click();
  </script>
</body>
</html>

Why parameterized queries (or parameterized filtering) work
- Principle: Separate code/structure from data. The program decides the allowed operations and how they are combined; user input is only provided as values (parameters) to those operations.
- In the vulnerable example, user text is directly interpolated into an expression that defines the filter logic — so a malicious input can inject operators or change the expression shape.
- In the safe example, the code parses the input into structured parameters (field, operator, literal value). The code only accepts known operators and fields and treats values as data. Even if the value contains characters that look like operators, they are never executed as code or used to change structure.
- In real databases you should use prepared statements / parameterized queries provided by the DB client library (e.g., parameter placeholders like ? or $1 and binding values). That ensures the DB engine treats the bound values as data, not SQL syntax.

